import React, { useEffect, useState, useRef } from "react";
import { useNavigate, Link } from "react-router-dom";
import html2pdf from "html2pdf.js";
import "../styles/Certificado.css";

const CertificadoBancario = () => {
  const navigate = useNavigate();
  const certificadoRef = useRef(null);

  const [usuario, setUsuario] = useState({
    nombre: "",
    documento: "",
    cuenta: "",
    tipoCuenta: "Ahorros",
    saldo: "$0 COP",
  });

  // 🔥 Obtener datos desde la base de datos
  useEffect(() => {
    const documentoGuardado = localStorage.getItem("documento");

    if (!documentoGuardado) {
      navigate("/inicio");
      return;
    }

    const obtenerUsuario = async () => {
      try {
        const response = await fetch(
          `http://127.0.0.1:8000/usuario-documento/${documentoGuardado}`
        );

        if (!response.ok) {
          throw new Error("No se pudo obtener usuario");
        }

        const data = await response.json();

        setUsuario({
          nombre: data.nombre || "Usuario",
          documento: data.documento || documentoGuardado,
          cuenta: data.numero_cuenta || "9800456721",
          tipoCuenta: data.tipo_cuenta || "Ahorros",
        });
      } catch (error) {
        console.error("Error al obtener usuario:", error);

        setUsuario({
          nombre: "Usuario",
          documento: documentoGuardado,
          cuenta: "9800456721",
          tipoCuenta: "Ahorros"
        });
      }
    };

    obtenerUsuario();
  }, [navigate]);

  // 🔥 Bloquear botón atrás
  useEffect(() => {
    window.history.pushState(null, "", window.location.href);

    const bloquear = () => {
      window.history.pushState(null, "", window.location.href);
    };

    window.addEventListener("popstate", bloquear);

    return () => {
      window.removeEventListener("popstate", bloquear);
    };
  }, []);

  // 🔥 Logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("usuario");
    localStorage.removeItem("documento");
    navigate("/inicio");
  };

  // 🔥 Descargar PDF EN UNA SOLA HOJA
  const descargarPDF = () => {
    if (!certificadoRef.current) return;

    const opciones = {
      margin: [0.3, 0.3, 0.3, 0.3],
      filename: `Certificado_${usuario.documento}.pdf`,
      image: {
        type: "jpeg",
        quality: 1,
      },
      html2canvas: {
        scale: 2,
        useCORS: true,
        scrollY: 0,
      },
      jsPDF: {
        unit: "in",
        format: "letter",
        orientation: "portrait",
      },
      pagebreak: {
        mode: ["avoid-all", "css", "legacy"],
      },
    };

    html2pdf()
      .set(opciones)
      .from(certificadoRef.current)
      .save();
  };

  // 🔥 Fecha actual
  const fechaActual = new Date().toLocaleDateString("es-CO", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  return (
    <div className="panel-financiero">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <ul>
          <li>
            <Link to="/cuenta">💷 Cuenta</Link>
          </li>

          <li>
            <Link to="#">📜 Historial Monetario</Link>
          </li>

          <li>
            <Link to="/transferencias">💳 Transferencias</Link>
          </li>

          <li>
            <Link to="/certificado" className="active">
              📄 Certificado Bancario
            </Link>
          </li>

          <li>
            <Link to="#">⚙️ Ajustes</Link>
          </li>
        </ul>

        <button className="logout" onClick={handleLogout}>
          🚪 Cerrar sesión
        </button>
      </aside>

      {/* CONTENIDO PRINCIPAL */}
      <main className="main">
        <header className="main-header">
          <h1>Certificado Bancario</h1>
        </header>

        <div className="certificado-page">
          <div className="certificado" ref={certificadoRef}>
            <div className="certificado-header">
              <h1>FINANCIERO</h1>
              <h2>CERTIFICADO BANCARIO</h2>
            </div>

            <div className="certificado-body">
              <p>
                La presente certifica que el(la) señor(a):{" "}
                <span className="texto-inline">{usuario.nombre}</span>
              </p>

              <p>
                Identificado(a) con Cédula de Ciudadanía No:{" "}
                <span className="texto-inline">{usuario.documento}</span>
              </p>

              <p>
                Es titular de una cuenta en nuestra entidad financiera con los
                siguientes datos:
              </p>

              <ul>
                <li>
                  <strong>Número de cuenta:</strong> {usuario.cuenta}
                </li>
                <li>
                  <strong>Tipo de cuenta:</strong> Ahorro
                </li>
              </ul>

              <p>
                Este certificado se expide en Bogotá D.C. el día:{" "}
                <span className="texto-inline">{fechaActual}</span>
              </p>
            </div>

            <div className="certificado-footer">
              <div className="firma-linea"></div>
              <p>Firma autorizada</p>
              <p>FINANCIERO</p>
            </div>
          </div>
        </div>

        {/* BOTÓN PDF */}
        <div className="pdf-btn-container">
          <button className="descargar-btn" onClick={descargarPDF}>
            📥 Descargar Certificado en PDF
          </button>
        </div>
      </main>
    </div>
  );
};

export default CertificadoBancario;
